# Check RBAC - Prometheus service account needs to read pods/services/endpoints in cockroachdb namespace
kubectl get clusterrolebinding -o json 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
for item in data['items']:
    subjects = item.get('subjects', [])
    for s in subjects:
        if s.get('name') == 'prometheus' and s.get('namespace') == 'monitoring':
            print(item['metadata']['name'], '->', item['roleRef']['name'])
" 2>/dev/null
